// TITAN PRO · V8 — Account data loaded from extracted JSON (14 sections per account).
// The data file `accounts-full.json` is generated by `scripts/extract-accounts.mjs`
// from the V7 sub-pages.

import accountsFull from './accounts-full.json';

// Convert kpis (with labels) to the V8 KPI card shape.
function kpiToCard(kpi, profile) {
  // Mark "Total Tayangan", "Total Suka", "Total Komentar", "Viral Posts" as gold (featured)
  // and "Engagement Rate" as pos (positive-tone)
  const label = kpi.label;
  const gold =
    /Total Tayangan|Total Suka|Total Komentar|Viral Posts/i.test(label) ||
    /Followers/i.test(label);
  const pos = /Engagement Rate/i.test(label);
  return { value: kpi.value, label, gold, pos };
}

export const accounts = Object.entries(accountsFull).map(([slug, a]) => {
  const profile = {
    ...a.profile,
    handle: a.profile.handle,
    platform: a.profile.platform,
    bio: a.profile.bio,
    niche: a.profile.niche,
    lokasi: a.profile.lokasi,
    url: a.profile.url,
    // Compat with existing UI
    followers: a.kpis.find((k) => k.label === 'Followers')?.value || '—',
    posts: a.kpis.find((k) => /Total (Video|Post)/i.test(k.label))?.value || '—',
    verified: a.profile.platform === 'instagram',
  };
  return {
    slug,
    profile,
    kpis: a.kpis.map(kpiToCard),
    topByViews: a.topByViews || [],
    topByLikes: a.topByLikes || [],
    topByComments: a.topByComments || [],
    tierDist: a.tierDist || [],
    hashtags: a.hashtags || [],
    mentions: a.mentions || [],
    insight: a.insight || { kekuatan: [], kelemahan: [], rekomendasi: [], analisis: '', posisi: '' },
    benchmark: a.benchmark || { industri: '', catatan: '' },
    growth: a.growth || { target: '', langkah: [] },
    dailyPerf: a.dailyPerf || [],
    monthlyPerf: a.monthlyPerf || [],
    yearly: a.yearly || [],
    duration: a.duration || [],
  };
});

export const accountBySlug = (slug) => accounts.find((a) => a.slug === slug);

export const homeGroups = {
  tiktok: accounts.filter((a) => a.profile.platform === 'tiktok'),
  instagram: accounts.filter((a) => a.profile.platform === 'instagram'),
};
